9		"entire.io/entire/git-sync/internal/internalbridge"
10		"entire.io/entire/git-sync/internal/validation"
11	)
12	
13	// Options configures a Client. It is intentionally small in the first public cut.
14	type Options struct {
15		HTTPClient *http.Client
16		Auth       AuthProvider
17	}
18	
19	// Client provides the public orchestration API for git-sync.
20	type Client struct {
21		httpClient *http.Client
22		auth       AuthProvider
23	}
24	
25	// New constructs a new Client.
26	func New(opts Options) *Client {
27		return &Client{httpClient: opts.HTTPClient, auth: opts.Auth}
28	}
29	
30	// Probe inspects a source remote and optional target remote.
31	func (c *Client) Probe(ctx context.Context, req ProbeRequest) (ProbeResult, error) {
32		if err := req.Validate(); err != nil {
33			return ProbeResult{}, err
34		}
35		cfg, err := c.buildProbeConfig(ctx, req)
36		if err != nil {
37			return ProbeResult{}, err
38		}
39		result, err := internalbridge.Probe(ctx, cfg)
40		if err != nil {
41			return ProbeResult{}, fmt.Errorf("probe: %w", err)
42		}
43		return internalbridge.FromProbeResult(result), nil
44	}
45	
46	// Plan computes ref actions without pushing.
47	func (c *Client) Plan(ctx context.Context, req PlanRequest) (PlanResult, error) {
48		if err := req.Validate(); err != nil {
49			return PlanResult{}, err
50		}
51		cfg, err := c.buildSyncConfig(ctx, req.Source, req.Target, req.Scope, req.Policy, req.CollectStats, true)
52		if err != nil {
53			return PlanResult{}, err
54		}
55		result, err := internalbridge.Run(ctx, cfg)
56		if err != nil {
57			return PlanResult{}, fmt.Errorf("plan: %w", err)
58		}
59		return internalbridge.FromSyncResult(result), nil
60	}
61	
62	// Sync executes a sync between two remotes.
63	func (c *Client) Sync(ctx context.Context, req SyncRequest) (SyncResult, error) {
64		if err := req.Validate(); err != nil {
65			return SyncResult{}, err
66		}
67		cfg, err := c.buildSyncConfig(ctx, req.Source, req.Target, req.Scope, req.Policy, req.CollectStats, false)
68		if err != nil {
69			return SyncResult{}, err
70		}
71		result, err := internalbridge.Run(ctx, cfg)
72		if err != nil {
73			return SyncResult{}, fmt.Errorf("sync: %w", err)
74		}
75		return internalbridge.FromSyncResult(result), nil
76	}
77	
78	// Replicate executes source-authoritative relay-only replication between two remotes.
79	func (c *Client) Replicate(ctx context.Context, req SyncRequest) (SyncResult, error) {
80		req.Policy.Mode = ModeReplicate
81		return c.Sync(ctx, req)
82	}
83	
84	func (c *Client) buildProbeConfig(ctx context.Context, req ProbeRequest) (internalbridge.Config, error) {
85		sourceAuth, err := c.authFor(ctx, req.Source, SourceRole)
86		if err != nil {
87			return internalbridge.Config{}, err
88		}
89		var target *internalbridge.Endpoint
90		targetAuth := internalbridge.EndpointAuth{}
91		if req.Target != nil {
92			resolvedTargetAuth, err := c.authFor(ctx, *req.Target, TargetRole)
93			if err != nil {
94				return internalbridge.Config{}, err
95			}
96			target = ptr(bridgeEndpoint(*req.Target))
97			targetAuth = bridgeEndpointAuth(resolvedTargetAuth)
98		}
99		return internalbridge.ProbeConfig(
100			bridgeEndpoint(req.Source),
101			bridgeEndpointAuth(sourceAuth),
102			target,
103			targetAuth,
104			internalbridge.ProtocolMode(req.Protocol),
105			req.IncludeTags,
106			req.AllRefs,
107			req.CollectStats,
108			req.ExcludeRefPrefixes,
109			c.httpClient,
110		), nil
111	}
112	
113	func (c *Client) buildSyncConfig(ctx context.Context, source Endpoint, target Endpoint, scope RefScope, policy SyncPolicy, collectStats, dryRun bool) (internalbridge.Config, error) {
114		sourceAuth, err := c.authFor(ctx, source, SourceRole)
115		if err != nil {
116			return internalbridge.Config{}, err
117		}
118		targetAuth, err := c.authFor(ctx, target, TargetRole)
119		if err != nil {
120			return internalbridge.Config{}, err
121		}
122		return internalbridge.SyncConfig(
123			bridgeEndpoint(source),
124			bridgeEndpointAuth(sourceAuth),
125			bridgeEndpoint(target),
126			bridgeEndpointAuth(targetAuth),
127			bridgeScope(scope),
128			bridgePolicy(policy),
129			collectStats,
130			dryRun,
131			c.httpClient,
132		), nil
133	}
134	
135	func (c *Client) authFor(ctx context.Context, endpoint Endpoint, role EndpointRole) (EndpointAuth, error) {
136		if c.auth == nil {
137			return EndpointAuth{}, nil
138		}
139		auth, err := c.auth.AuthFor(ctx, endpoint, role)
140		if err != nil {
141			return EndpointAuth{}, fmt.Errorf("resolve auth for %s: %w", role, err)
142		}
143		return auth, nil
144	}
145	
146	func (r SyncRequest) Validate() error {
147		return validateSyncFields(r.Source, r.Target, r.Scope, r.Policy)
148	}
149	
150	func (r PlanRequest) Validate() error {
151		return validateSyncFields(r.Source, r.Target, r.Scope, r.Policy)
152	}
153	
154	// validateSyncFields validates the fields shared by SyncRequest and
155	// PlanRequest, whose Validate methods are otherwise identical.
156	func validateSyncFields(source, target Endpoint, scope RefScope, policy SyncPolicy) error {
157		if source.URL == "" {
158			return errors.New("source URL is required")
159		}
160		if target.URL == "" {
161			return errors.New("target URL is required")
162		}
163		if err := validateOperationMode(policy.Mode); err != nil {
164			return err
165		}
166		if err := policy.Validate(); err != nil {
167			return err
168		}
169		if _, err := validation.NormalizeProtocolMode(string(policy.Protocol)); err != nil {
170			return fmt.Errorf("normalize protocol: %w", err)
171		}
172		if _, err := validation.ValidateMappings(validationMappings(scope.Mappings), scope.AllRefs); err != nil {
173			return fmt.Errorf("validate mappings: %w", err)
174		}
175		return nil
176	}
177	
178	func (r ProbeRequest) Validate() error {
179		if r.Source.URL == "" {
180			return errors.New("source URL is required")
181		}
182		if r.Target != nil && r.Target.URL == "" {
183			return errors.New("target URL is required when target endpoint is provided")
184		}
185		if _, err := validation.NormalizeProtocolMode(string(r.Protocol)); err != nil {
186			return fmt.Errorf("normalize protocol: %w", err)
187		}
188		return nil
189	}
190	
191	func bridgeEndpoint(ep Endpoint) internalbridge.Endpoint {
192		return internalbridge.Endpoint{
193			URL:                    ep.URL,
194			FollowInfoRefsRedirect: ep.FollowInfoRefsRedirect,
195		}
196	}
197	
198	func bridgeEndpointAuth(auth EndpointAuth) internalbridge.EndpointAuth {
199		return internalbridge.EndpointAuth{
200			Username:      auth.Username,
201			Token:         auth.Token,
202			BearerToken:   auth.BearerToken,
203			SkipTLSVerify: auth.SkipTLSVerify,
204		}
205	}
206	
207	func bridgeScope(scope RefScope) internalbridge.RefScope {
208		mappings := make([]internalbridge.RefMapping, 0, len(scope.Mappings))
209		for _, mapping := range scope.Mappings {
210			mappings = append(mappings, internalbridge.RefMapping{
211				Source: mapping.Source,
212				Target: mapping.Target,
213			})
214		}
215		return internalbridge.RefScope{
216			Branches:           append([]string(nil), scope.Branches...),
217			Mappings:           mappings,
218			AllRefs:            scope.AllRefs,
219			ExcludeRefPrefixes: append([]string(nil), scope.ExcludeRefPrefixes...),
220		}
221	}
222	
223	func bridgePolicy(policy SyncPolicy) internalbridge.SyncPolicy {
224		return internalbridge.SyncPolicy{
225			Mode:           internalbridge.OperationMode(policy.Mode),
226			IncludeTags:    policy.IncludeTags,
227			ForceWithLease: policy.ForceWithLease,
228			ForceBlind:     policy.ForceBlind,
229			Prune:          policy.Prune,
230			BestEffort:     policy.BestEffort,
231			Protocol:       internalbridge.ProtocolMode(policy.Protocol),
232		}
233	}
234	
235	func validateOperationMode(mode OperationMode) error {
236		switch mode {
237		case "", ModeSync, ModeReplicate:
238			return nil
239		default:
240			return fmt.Errorf("unsupported operation mode %q", mode)
241		}
242	}
243	
244	func ptr[T any](v T) *T {
245		return &v
246	}
247	
248	func validationMappings(mappings []RefMapping) []validation.RefMapping {
249		out := make([]validation.RefMapping, 0, len(mappings))
250		for _, mapping := range mappings {
251			out = append(out, validation.RefMapping{
252				Source: mapping.Source,
253				Target: mapping.Target,
254			})
255		}
256		return out
