2	
3	import (
4		"bufio"
5		"bytes"
6		"fmt"
7		"io"
8	
9		"github.com/go-git/go-git/v6/plumbing/format/pktline"
10	)
11	
12	// PacketType represents the type of a pkt-line packet.
13	type PacketType int
14	
15	const (
16		PacketData        PacketType = iota
17		PacketFlush                  // 0000
18		PacketDelim                  // 0001
19		PacketResponseEnd            // 0002
20	)
21	
22	// PacketReader reads pkt-line formatted data. It reuses a fixed header buffer
23	// and a growable payload buffer to reduce allocations (issue #17).
24	type PacketReader struct {
25		r      *bufio.Reader
26		header [4]byte
27		buf    []byte
28	}
29	
30	func NewPacketReader(r io.Reader) *PacketReader {
31		if br, ok := r.(*bufio.Reader); ok {
32			return &PacketReader{r: br, buf: make([]byte, 0, 1024)}
33		}
34		return &PacketReader{r: bufio.NewReaderSize(r, 65536), buf: make([]byte, 0, 1024)}
35	}
36	
37	// BufReader returns the underlying buffered reader for direct access
38	// (needed by sideband demuxer after switching to pack stream).
39	func (pr *PacketReader) BufReader() *bufio.Reader {
40		return pr.r
41	}
42	
43	// ReadPacket reads the next pkt-line packet. The returned payload slice is
44	// only valid until the next call to ReadPacket.
45	func (pr *PacketReader) ReadPacket() (PacketType, []byte, error) {
46		if _, err := io.ReadFull(pr.r, pr.header[:]); err != nil {
47			return PacketData, nil, fmt.Errorf("read pktline header: %w", err)
48		}
49	
50		switch string(pr.header[:]) {
51		case "0000":
52			return PacketFlush, nil, nil
53		case "0001":
54			return PacketDelim, nil, nil
55		case "0002":
56			return PacketResponseEnd, nil, nil
57		}
58	
59		n, err := parseHexLength(pr.header)
60		if err != nil {
61			return PacketData, nil, err
62		}
63		if n < 4 || n > pktline.MaxSize {
64			return PacketData, nil, pktline.ErrInvalidPktLen
65		}
66		if n == 4 {
67			return PacketData, pr.buf[:0], nil
68		}
69	
70		payloadLen := n - 4
71		if payloadLen > cap(pr.buf) {
72			pr.buf = make([]byte, payloadLen)
73		} else {
74			pr.buf = pr.buf[:payloadLen]
75		}
76		if _, err := io.ReadFull(pr.r, pr.buf); err != nil {
77			return PacketData, nil, fmt.Errorf("read pktline payload: %w", err)
78		}
79		return PacketData, pr.buf, nil
80	}
81	
82	// readRawPktLine reads one pkt-line and returns its type plus the verbatim
83	// on-wire bytes — the 4-byte length header followed by any payload — so callers
84	// that must relay or accumulate the exact wire framing (unlike ReadPacket,
85	// which yields only the payload) can do so. scratch is reused as backing
86	// storage and grown as needed; pass the slice returned by the previous call to
87	// avoid per-packet allocation. The returned slice aliases scratch and is valid
88	// only until the next call.
89	func readRawPktLine(br *bufio.Reader, scratch []byte) (PacketType, []byte, error) {
90		if cap(scratch) < 4 {
91			scratch = make([]byte, 4)
92		}
93		frame := scratch[:4]
94		if _, err := io.ReadFull(br, frame); err != nil {
95			return PacketData, nil, fmt.Errorf("read pktline header: %w", err)
96		}
97		switch string(frame) {
98		case "0000":
99			return PacketFlush, frame, nil
100		case "0001":
101			return PacketDelim, frame, nil
102		case "0002":
103			return PacketResponseEnd, frame, nil
104		}
105	
106		var header [4]byte
107		copy(header[:], frame)
108		n, err := parseHexLength(header)
109		if err != nil {
110			return PacketData, nil, err
111		}
112		if n < 4 || n > pktline.MaxSize {
113			return PacketData, nil, pktline.ErrInvalidPktLen
114		}
115		if n > cap(scratch) {
116			grown := make([]byte, n)
117			copy(grown, frame)
118			scratch = grown
119		} else {
120			scratch = scratch[:n]
121		}
122		if n > 4 {
123			if _, err := io.ReadFull(br, scratch[4:n]); err != nil {
124				return PacketData, nil, fmt.Errorf("read pktline payload: %w", err)
125			}
126		}
127		return PacketData, scratch[:n], nil
128	}
129	
130	func parseHexLength(header [4]byte) (int, error) {
131		var n int
132		for _, b := range header {
133			v, ok := hexVal(b)
134			if !ok {
135				return 0, pktline.ErrInvalidPktLen
136			}
137			n = 16*n + int(v)
138		}
139		return n, nil
140	}
141	
142	func hexVal(b byte) (byte, bool) {
143		switch {
144		case b >= '0' && b <= '9':
145			return b - '0', true
146		case b >= 'a' && b <= 'f':
147			return b - 'a' + 10, true
148		case b >= 'A' && b <= 'F':
149			return b - 'A' + 10, true
150		default:
151			return 0, false
152		}
153	}
154	
155	// EncodeCommand builds a pkt-line encoded v2 command request.
156	func EncodeCommand(command string, capArgs, cmdArgs []string) ([]byte, error) {
157		var buf bytes.Buffer
158		if _, err := pktline.Writef(&buf, "command=%s\n", command); err != nil {
159			return nil, fmt.Errorf("write command: %w", err)
160		}
161		for _, arg := range capArgs {
162			if _, err := pktline.Writef(&buf, "%s\n", arg); err != nil {
163				return nil, fmt.Errorf("write capability arg: %w", err)
164			}
165		}
166		if len(cmdArgs) > 0 {
167			if err := pktline.WriteDelim(&buf); err != nil {
168				return nil, fmt.Errorf("write delimiter: %w", err)
169			}
170			for _, arg := range cmdArgs {
171				if _, err := pktline.Writef(&buf, "%s\n", arg); err != nil {
172					return nil, fmt.Errorf("write command arg: %w", err)
173				}
174			}
175		}
176		if err := pktline.WriteFlush(&buf); err != nil {
177			return nil, fmt.Errorf("write flush: %w", err)
178		}
179		return buf.Bytes(), nil
180	}
