		t.Fatalf("Close() error: %v", err)
	}
	if err := wrapped.Close(); err != nil {
		t.Fatalf("second Close() error: %v", err)
	}
	if cc.closes != 1 {
		t.Fatalf("underlying closer closed %d times, want 1", cc.closes)
	}
}
